#include <stdio.h>
#include <stdlib.h>

int main() {
  int numbers[] = {1, 2, 3, 4, 5};
  int size = 5;
  double sum = 0.0;

  for (int i = 0; i < size; i++) {
    sum += numbers[i];
  }
  double average = sum / size;

  printf("Ədədlərin ortalaması: %f\n", average);
  return 0;
}
// Output:
// Ədədlərin ortalaması: 3.000000

#include <stdio.h>

#ifdef _WIN32
#include <windows.h>
#define SLEEP(ms) Sleep(ms)
#else
#include <unistd.h>
#define SLEEP(ms) usleep((ms) * 1000)
#endif

int main() {
  printf("3 saniyə gözləyin...\n");
  SLEEP(3000);
  printf("Gözləmə bitdi!\n");
  return 0;
}
// Output:
// 3 saniyə gözləyin...
// (3 saniyə sonra)
// Gözləmə bitdi!

#include <stdio.h>

int main() {
  FILE* file = fopen("example.txt", "w");
  if (file == NULL) {
    printf("Fayl yaradılmadı\n");
    return 1;
  }

  fprintf(file, "Bu portativ C kodudur!\n");
  fclose(file);

  file = fopen("example.txt", "r");
  if (file == NULL) {
    printf("Fayl oxunmadı\n");
    return 1;
  }

  char buffer[100];
  fgets(buffer, 100, file);
  printf("Faylın məzmunu: %s", buffer);
  fclose(file);
  return 0;
}
// Output:
// Faylın məzmunu: Bu portativ C kodudur!

